#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int cmp_asc(const void *a, const void *b) { return *(char*)a - *(char*)b; }
int cmp_desc(const void *a, const void *b) { return *(char*)b - *(char*)a; }

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char A_raw[100005], B_raw[100005];
        scanf("%s", A_raw);
        scanf("%s", B_raw);
        // sort Alice ascending
        qsort(A_raw, N, sizeof(char), cmp_asc);
        // sort Bob descending
        qsort(B_raw, N, sizeof(char), cmp_desc);
        int a_keep = (N+1)/2; // ceil(N/2)
        int b_keep = N/2;     // floor(N/2)
        char *A = (char*)malloc(a_keep * sizeof(char));
        char *B = (char*)malloc(b_keep * sizeof(char));
        memcpy(A, A_raw, a_keep);
        memcpy(B, B_raw, b_keep);
        int aL=0, aR=a_keep-1, bL=0, bR=b_keep-1;
        int L=0, R=2*N-1;
        char *ans = (char*)malloc((2*N+1)*sizeof(char));
        for(int turn=0; turn<2*N; ++turn){
            if(turn%2==0){ // Alice
                if(aL<=aR && (bL>bR || A[aL] < B[bL])){
                    ans[L++] = A[aL++];
                }else{
                    ans[R--] = A[aR--];
                }
            }else{ // Bob
                if(bL<=bR && (aL>aR || A[aL] < B[bL])){
                    ans[L++] = B[bL++];
                }else{
                    ans[R--] = B[bR--];
                }
            }
        }
        ans[2*N] = '\0';
        printf("%s\n", ans);
        free(A); free(B); free(ans);
    }
    return 0;
}

