import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            char[] a = fs.next().toCharArray();
            char[] b = fs.next().toCharArray();
            Arrays.sort(a); // ascending
            // sort b descending
            Character[] bObj = new Character[N];
            for (int i = 0; i < N; i++) bObj[i] = b[i];
            Arrays.sort(bObj, Collections.reverseOrder());
            for (int i = 0; i < N; i++) b[i] = bObj[i];
            int aKeep = (N + 1) / 2;
            int bKeep = N / 2;
            char[] aUse = Arrays.copyOfRange(a, 0, aKeep);
            char[] bUse = Arrays.copyOfRange(b, 0, bKeep);
            int aL = 0, aR = aKeep - 1, bL = 0, bR = bKeep - 1;
            int L = 0, R = 2 * N - 1;
            char[] ans = new char[2 * N];
            for (int turn = 0; turn < 2 * N; turn++) {
                if (turn % 2 == 0) { // Alice
                    if (aL <= aR && (bL > bR || aUse[aL] < bUse[bL])) {
                        ans[L++] = aUse[aL++];
                    } else {
                        ans[R--] = aUse[aR--];
                    }
                } else { // Bob
                    if (bL <= bR && (aL > aR || aUse[aL] < bUse[bL])) {
                        ans[L++] = bUse[bL++];
                    } else {
                        ans[R--] = bUse[bR--];
                    }
                }
            }
            out.append(new String(ans)).append('\n');
        }
        System.out.print(out.toString());
    }

    // Fast scanner for Java
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
    }
}

